const nameMap = {
  '@yourusername:beeper.com': 'Your Name'
  // Add more mappings as needed
};

let fullChat = "Please summarize this chat conversation:\n\n";

for (let item of $input.all()) {
  let sender = item.json.sender;
  let text = item.json.body;
  let displayName = nameMap[sender] || sender;

  fullChat += `[${displayName}]: ${text}\n`;
}

return [{ json: { chat_history: fullChat } }];
